        for cite in citation_list:
            pub_num = cite.get('publication_number', '')
            if pub_num in uc_pub_numbers:
                citing_mappings.append({
                    'citing_assignee': assignee,
                    'cited_pub_number': pub_num,
                    'citing_patent_info': patents_info
                })
    except:
